{"title":"Top Flow Failure Reasons","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "title": "Failed Nodes & Reasons",
  "data": {
    "url": {
      "index": "otel-v1-apm-span-*", 
      "body": {
        "size": 0,
        "query": {
          "term": {
            "name": "FLOW_NODE_EXECUTION_FAILED"
          }
        },
        "aggs": {
          "nested_events": {
            "nested": {
              "path": "events"
            },
            "aggs": {
              "by_node_id": {
                "terms": {
                  "field": "events.attributes.node_id.keyword",
                  "size": 10
                },
                "aggs": {
                  "by_reason": {
                    "terms": {
                      "field": "events.attributes.failure_reason.keyword",
                      "size": 5
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "format": {
      "property": "aggregations.nested_events.by_node_id.buckets"
    }
  },
  "transform": [
    {
      "flatten": ["by_reason.buckets"],
      "as": ["reason_bucket"]
    },
    {
      "calculate": "datum.reason_bucket.key",
      "as": "Failure Reason"
    },
    {
      "calculate": "datum.reason_bucket.doc_count",
      "as": "Count"
    },
    {
      "calculate": "datum.key",
      "as": "Node ID"
    }
  ],
  "mark": "bar",
  "encoding": {
    "x": {
      "field": "Node ID",
      "type": "nominal",
      "axis": {"labelAngle": 0}
    },
    "y": {
      "field": "Count",
      "type": "quantitative"
    },
    "color": {
      "field": "Failure Reason",
      "type": "nominal"
    },
    "tooltip": [
      {"field": "Node ID", "type": "nominal"},
      {"field": "Failure Reason", "type": "nominal"},
      {"field": "Count", "type": "quantitative"}
    ]
  }
}"}}

{"title":"Flow Failure Breakdown","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "title": Client vs Server Errors
  "data": {
    "url": {
      "index": "otel-v1-apm-span-*",
      "body": {
        "size": 0,
        "query": {
          "term": {
            "name": "FLOW_FAILED"
          }
        },
        "aggs": {
          "nested_events": {
            "nested": {
              "path": "events"
            },
            "aggs": {
              "by_error_type": {
                "terms": {
                  "field": "events.attributes.error_type.keyword",
                  "size": 10
                }
              }
            }
          }
        }
      }
    },
    "format": {
      "property": "aggregations.nested_events.by_error_type.buckets"
    }
  },
  "transform": [
    {
      "calculate": "datum.key",
      "as": "Error Category"
    },
    {
      "calculate": "datum.doc_count",
      "as": "Count"
    }
  ],
  "mark": {
    "type": "arc",
    "innerRadius": 50,
    "tooltip": true
  },
  "encoding": {
    "theta": {
      "field": "Count",
      "type": "quantitative"
    },
    "color": {
      "field": "Error Category",
      "type": "nominal",
      "scale": {
        "scheme": "category10"
      },
      "legend": {
        "title": "Error Type"
      }
    },
    "tooltip": [
      {
        "field": "Error Category",
        "type": "nominal"
      },
      {
        "field": "Count",
        "type": "quantitative"
      }
    ]
  }
}"}}

{"title":"Average time per node","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "title": "Average Execution Time per Node (ms)",
  "data": {
    "url": {
      "index": "otel-v1-apm-span-*",
      "body": {
        "size": 0,
        "query": {
          "bool": {
            "must": [
              { "match_phrase": { "name": "FLOW_NODE_EXECUTION_COMPLETED" } }
            ]
          }
        },
        "aggs": {
          "traces": {
            "terms": { "field": "traceId", "size": 100 },
            "aggs": {
              "spans_sequence": {
                "top_hits": {
                  "_source": {
                    "includes": ["events", "name"]
                  },
                  "size": 50
                }
              }
            }
          }
        }
      }
    },
    "format": {
      "property": "aggregations.traces.buckets"
    }
  },
  "transform": [
    {
      "comment": "1. Flatten the hits from the traces",
      "flatten": ["spans_sequence.hits.hits"],
      "as": ["hit"]
    },
    {
      "comment": "2. Flatten the events array inside each span",
      "flatten": ["hit._source.events"],
      "as": ["event_entry"]
    },
    {
      "comment": "3. Filter for Node Completion events only",
      "filter": "datum.event_entry.name == 'FLOW_NODE_EXECUTION_COMPLETED'"
    },
    {
      "comment": "4. Extract Node ID",
      "calculate": "datum.event_entry.attributes.node_id",
      "as": "Node ID"
    },
    {
      "comment": "5. Extract Duration (convert string to number)",
      "calculate": "toNumber(datum.event_entry.attributes.duration_ms)",
      "as": "Duration_MS"
    }
  ],
  "mark": "bar",
  "encoding": {
    "y": {
      "field": "Node ID",
      "type": "nominal",
      "sort": "-x",
      "title": "Flow Node",
      "axis": {"labelFontSize": 12, "titleFontSize": 14}
    },
    "x": {
      "field": "Duration_MS",
      "type": "quantitative",
      "aggregate": "mean",
      "title": "Average Duration (ms)"
    },
    "color": {
      "field": "Node ID",
      "type": "nominal",
      "legend": null,
      "scale": {"scheme": "tableau10"}
    },
    "tooltip": [
      {"field": "Node ID", "title": "Node"},
      {"field": "Duration_MS", "aggregate": "mean", "format": ".2f", "title": "Avg Time (ms)"},
      {"field": "Duration_MS", "aggregate": "min", "title": "Min Time (ms)"},
      {"field": "Duration_MS", "aggregate": "max", "title": "Max Time (ms)"},
      {"field": "Duration_MS", "aggregate": "count", "title": "Total Executions"}
    ]
  },
  "layer": [
    {
      "mark": "bar"
    },
    {
      "mark": {
        "type": "text",
        "align": "left",
        "baseline": "middle",
        "dx": 3
      },
      "encoding": {
        "text": {
          "field": "Duration_MS",
          "aggregate": "mean",
          "format": ".1f"
        }
      }
    }
  ]
}"}}
